import { PrismaClient } from '@prisma/client'

const prisma = new PrismaClient()

export async function processTasks() {
  console.log('Processing tasks...')

  const unprocessedTasks = await prisma.task.findMany({
    where: {
      isProcessed: false
    }
  })

  console.log(`Found ${unprocessedTasks.length} unprocessed tasks`)

  for (const task of unprocessedTasks) {
    await prisma.task.update({
      where: {
        id: task.id
      },
      data: {
        isProcessed: true
      }
    })
    console.log(`Processed task ${task.id}: ${task.description}`)
  }

  console.log('Task processing complete')
  return { processedCount: unprocessedTasks.length }
}

