import { createTask as createTaskAction, triggerJob as triggerJobAction } from '@wasp/actions'
import { PrismaClient } from '@prisma/client'

const prisma = new PrismaClient()

export const triggerJob = triggerJobAction(async (args, context) => {
  console.log('Triggering processTasks job...')
  const result = await processTasks.submit()
  console.log('Job submitted successfully')
  return { success: true, jobId: result.id }
})

export const createTask = createTaskAction(async ({ description }, context) => {
  const task = await prisma.task.create({
    data: {
      description,
      isProcessed: false
    }
  })
  return task
})

