import { useState } from 'react'
import { getTasks } from '@wasp/queries'
import { createTask, triggerJob } from '@wasp/actions'
import { useQuery, useAction } from '@wasp/queries'
import './Main.css'

export function MainPage() {
  const { data: tasks, refetch } = useQuery(getTasks)
  const createTaskFn = useAction(createTask)
  const triggerJobFn = useAction(triggerJob)

  const [newTaskDescription, setNewTaskDescription] = useState('')

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!newTaskDescription.trim()) return

    try {
      await createTaskFn({ description: newTaskDescription })
      setNewTaskDescription('')
      refetch()
    } catch (error) {
      console.error('Error creating task:', error)
    }
  }

  const handleTriggerJob = async () => {
    try {
      await triggerJobFn({})
      // Wait a moment for the job to process, then refetch
      setTimeout(() => refetch(), 1000)
    } catch (error) {
      console.error('Error triggering job:', error)
    }
  }

  return (
    <main className="container">
      <h1 className="title">Background Jobs Demo</h1>

      <div className="task-form">
        <h2>Create New Task</h2>
        <form onSubmit={handleCreateTask}>
          <input
            type="text"
            value={newTaskDescription}
            onChange={(e) => setNewTaskDescription(e.target.value)}
            placeholder="Enter task description..."
            className="task-input"
          />
          <button type="submit" className="button button-filled">
            Add Task
          </button>
        </form>
      </div>

      <div className="job-controls">
        <h2>Background Job</h2>
        <button onClick={handleTriggerJob} className="button button-filled">
          Trigger Background Job
        </button>
        <p className="hint">
          This will process all unprocessed tasks in the background.
        </p>
      </div>

      <div className="task-list">
        <h2>Tasks ({tasks?.length || 0})</h2>
        {tasks && tasks.length > 0 ? (
          <ul className="tasks">
            {tasks.map((task) => (
              <li key={task.id} className="task">
                <span className="task-description">{task.description}</span>
                <span
                  className={`task-status ${
                    task.isProcessed ? 'processed' : 'unprocessed'
                  }`}
                >
                  {task.isProcessed ? 'Processed' : 'Unprocessed'}
                </span>
              </li>
            ))}
          </ul>
        ) : (
          <p className="no-tasks">No tasks yet. Create one above!</p>
        )}
      </div>
    </main>
  )
}

