import { createTask as createTaskAction, triggerJob as triggerJobAction } from 'wasp/server/operations/actions'
import { PrismaClient } from '@prisma/client'

const prisma = new PrismaClient()

export const triggerJob = triggerJobAction(async (args: any, context: any) => {
  console.log('Processing tasks in background...')

  const unprocessedTasks = await prisma.task.findMany({
    where: {
      isProcessed: false
    }
  })

  console.log(`Found ${unprocessedTasks.length} unprocessed tasks`)

  for (const task of unprocessedTasks) {
    await prisma.task.update({
      where: {
        id: task.id
      },
      data: {
        isProcessed: true
      }
    })
    console.log(`Processed task ${task.id}: ${task.description}`)
  }

  console.log('Task processing complete')
  return { success: true, processedCount: unprocessedTasks.length }
})

export const createTask = createTaskAction(async ({ description }: { description: string }, context: any) => {
  const task = await prisma.task.create({
    data: {
      description,
      isProcessed: false
    }
  })
  return task
})

